import matplotlib
matplotlib.use("Agg")
import matplotlib.pyplot as plt
import matplotlib.colors as mcolors
import numpy as np
import pandas as pd
import json, gzip, base64, os
from matplotlib.lines import Line2D

# ── Pre-render EAB spread maps for all years (2002-2022) ──
# Upstream: spread_df from analysis.track_b_spread
# Output: 21 PNG files saved to ./frames/

print("Pre-rendering EAB spread maps to ./frames/ ...")

os.makedirs("./frames", exist_ok=True)

# ── Embedded state outlines (Census Bureau 20m GeoJSON, gzipped) ──
_STATES_B64 = ""

def _load_states():
    raw = gzip.decompress(base64.b64decode(_STATES_B64))
    return json.loads(raw)

_states_geo = _load_states()

def _draw_states(ax, color="#555560", lw=0.6):
    for feat in _states_geo["features"]:
        geom = feat["geometry"]
        if geom["type"] == "Polygon":
            for ring in geom["coordinates"]:
                xs = [c[0] for c in ring]
                ys = [c[1] for c in ring]
                ax.plot(xs, ys, color=color, linewidth=lw, zorder=0)
        elif geom["type"] == "MultiPolygon":
            for polygon in geom["coordinates"]:
                for ring in polygon:
                    xs = [c[0] for c in ring]
                    ys = [c[1] for c in ring]
                    ax.plot(xs, ys, color=color, linewidth=lw, zorder=0)

# ── Prepare data once ──
_df = spread_df.copy()
_DEFAULT_ASH = 10000
_df["_ash_display"] = np.where(
    (_df["has_eab"] == 1) & (_df["ash_estimate"] == 0),
    _DEFAULT_ASH, _df["ash_estimate"]
)
_total_ash_sum = _df["ash_estimate"].sum()
_aspect = 1 / np.cos(np.radians(37))

# Non-EAB counties (constant across all frames)
_never_eab_ash = _df[(_df["has_eab"] == 0) & (_df["_ash_display"] > 0)].copy()
_never_eab_ash["_log_ash"] = np.log10(_never_eab_ash["_ash_display"].clip(lower=1))
_no_ash = _df[(_df["has_eab"] == 0) & (_df["_ash_display"] == 0)]

# All EAB counties (will be split per year)
_all_eab = _df[_df["has_eab"] == 1].copy()
_all_eab["_log_ash"] = np.log10(_all_eab["_ash_display"].clip(lower=1))

# ── Render each year ──
for _yr in range(2002, 2023):
    fig, ax = plt.subplots(figsize=(12, 7), dpi=100)
    fig.patch.set_facecolor("#1D1D20")
    ax.set_facecolor("#1D1D20")

    _draw_states(ax)

    # EAB counties detected by this year
    _eab_hit = _all_eab[_all_eab["year_detected"] <= _yr]
    # EAB counties not yet detected — show as green
    _eab_future = _all_eab[_all_eab["year_detected"] > _yr]

    # Combine green layers: never-EAB ash + future-EAB ash
    _green = pd.concat([_never_eab_ash, _eab_future[_eab_future["_ash_display"] > 0]])

    # Layer 1: Green ash dots
    if len(_green) > 0:
        _g_log = np.log10(_green["_ash_display"].clip(lower=1))
        _g_sizes = 4 + 51 * (_g_log - _g_log.min()) / (_g_log.max() - _g_log.min() + 1e-9)
        ax.scatter(
            _green["lon"], _green["lat"],
            c=_g_log.values, cmap=plt.cm.Greens,
            norm=mcolors.Normalize(vmin=_g_log.min(), vmax=_g_log.max()),
            s=_g_sizes, alpha=0.75, edgecolors="none", zorder=2
        )

    # Layer 2: Orange EAB dots
    if len(_eab_hit) > 0:
        _e_log = _eab_hit["_log_ash"]
        _e_sizes = 6 + 49 * (_e_log - _e_log.min()) / (_e_log.max() - _e_log.min() + 1e-9)
        _e_sizes = np.where(_eab_hit["ash_estimate"].values == 0, 6, _e_sizes.values)
        ax.scatter(
            _eab_hit["lon"], _eab_hit["lat"],
            c="#D55E00", s=_e_sizes,
            alpha=0.85, edgecolors="#8B2500", linewidths=0.4, zorder=3
        )

    # Gray no-ash dots
    if len(_no_ash) > 0:
        ax.scatter(
            _no_ash["lon"], _no_ash["lat"],
            c="#383840", s=1.5, alpha=0.35, edgecolors="none", zorder=1
        )

    ax.set_xlim(-128, -65)
    ax.set_ylim(24, 50)
    ax.set_aspect(_aspect)
    for sp in ax.spines.values():
        sp.set_edgecolor("#555560")
    ax.tick_params(colors="#909094", labelsize=9)
    ax.set_xlabel("Longitude", fontsize=11, color="#909094")
    ax.set_ylabel("Latitude", fontsize=11, color="#909094")
    ax.set_title(f"EAB Spread Map \u2014 {_yr}",
                 fontsize=16, fontweight="bold", color="#fbfbff", pad=14)

    # Counter
    _n_hit = len(_eab_hit)
    _eab_ash_sum = _eab_hit["ash_estimate"].sum() if len(_eab_hit) > 0 else 0
    _pct = (_eab_ash_sum / _total_ash_sum * 100) if _total_ash_sum > 0 else 0
    ax.text(0.02, 0.04,
            f"{_n_hit:,} counties affected  |  {_pct:.1f}% of ash trees in EAB zones",
            transform=ax.transAxes, fontsize=10, color="#ffd400", fontweight="bold",
            verticalalignment="bottom",
            bbox=dict(boxstyle="round,pad=0.3", facecolor="#1D1D20",
                      edgecolor="#ffd400", alpha=0.7))

    # Legend
    ax.legend(
        handles=[
            Line2D([0], [0], marker="o", color="w", markerfacecolor="#2ca02c",
                   markersize=9, label="Ash habitat (no EAB)"),
            Line2D([0], [0], marker="o", color="w", markerfacecolor="#D55E00",
                   markeredgecolor="#8B2500", markersize=9, label="EAB detected"),
        ],
        loc="upper left", fontsize=10, framealpha=0.85,
        facecolor="#2a2a2d", edgecolor="#555560", labelcolor="#fbfbff"
    )

    plt.tight_layout(pad=0.5)

    # Save to file
    fig.savefig(f"./frames/{_yr}.png", bbox_inches="tight", facecolor=fig.get_facecolor())
    plt.close(fig)

    print(f"  {_yr}: {_n_hit:,} counties, {_pct:.1f}%")

print(f"\nDone. {len(os.listdir('./frames'))} frames saved to ./frames/")

# Cleanup
del fig, ax, _df, _all_eab, _eab_hit, _eab_future, _green, _no_ash
del _never_eab_ash, _states_geo, _draw_states, _load_states
del _yr, _n_hit, _eab_ash_sum, _pct, _total_ash_sum, _aspect
del _DEFAULT_ASH, _STATES_B64, Line2D
